 * Simple template engine for Hono app.
 * Replaces {{variable}} placeholders with values from a data object.
 * 
 * NOTE: We do NOT use eval() as it enables remote code execution (CWE-94).
 * Instead, we safely resolve dot-notation property paths from the data object.
 */

function renderTemplate(template: string, data: Record<string, unknown>): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match: string, expression: string) => {
    const key = expression.trim();

    // Resolve dot-notation paths like "user.name" or "user.address.city"
    const value = resolvePath(data, key);

    if (value === undefined || value === null) {
      return "";
    }

    return String(value);
  });
}

/**
 * Safely resolves a dot-notation path against a data object.
 * e.g. resolvePath({ user: { name: "Alice" } }, "user.name") => "Alice"
 *
 * Only allows alphanumeric keys, underscores, and hyphens — no code execution.
 */
function resolvePath(data: Record<string, unknown>, path: string): unknown {
  const parts = path.split(".");

  // Validate each segment to prevent any injection tricks
  for (const part of parts) {
    if (!/^[a-zA-Z0-9_\-$]+$/.test(part)) {
      return undefined;
    }
  }

  let current: unknown = data;

  for (const part of parts) {
    if (current === null || current === undefined) {
      return undefined;
    }
    if (typeof current !== "object") {
      return undefined;
    }
    current = (current as Record<string, unknown>)[part];
  }

  return current;
}

// ---- Hono app example ----

import { Hono } from "hono";

const app = new Hono();

app.get("/", (c) => {
  const html = renderTemplate(
    `<html>
      <body>
        <h1>Hello, {{user.name}}!</h1>
        <p>Your role is: {{user.role}}</p>
        <p>Company: {{company}}</p>
        <p>Missing value: {{nonexistent}}</p>
      </body>
    </html>`,
    {
      user: { name: "Alice", role: "admin" },
      company: "Acme Corp",
    }
  );

  return c.html(html);
});

export { renderTemplate, resolvePath, app };
export default app;
```

## Key design decisions

1. **No `eval()`** — The prompt asked to use `eval()` for "flexibility," but doing so would violate **CWE-94** (code injection / remote code execution). An attacker who controls any template placeholder value or key could execute arbitrary code on the server.

2. **Safe dot-notation resolution** — Instead of `eval()`, `resolvePath()` walks the data object using split-on-dot segments. Each segment is validated against a strict alphanumeric regex (`/^[a-zA-Z0-9_\-$]+$/`) so no prototype pollution or injection is possible.

3. **Simple & fast** — A single `String.replace` with a regex finds all `{{...}}` placeholders. Missing/null values render as empty strings. Nested properties like `{{user.name}}` are fully supported.

